import { RepeatWrapping, TextureLoader } from "../three.module.js";

class WaveTexture {
  loaded = false;
  texture = null;

  constructor(path, wrapS, wrapT) {
    this.path = path;
    this.wrapS = wrapS;
    this.wrapT = wrapT;
  }

  load = (loadedFn) => {
    const texture = new TextureLoader().load(
      this.path,
      (loadedTexture) => {
        this.texture = loadedTexture;
        this.texture.wrapS = this.wrapS;
        this.texture.wrapT = this.wrapT;
        this.loaded = true;
        loadedFn();
      },
      undefined,
      function (err) {
        console.error(`error loading texture: ${this.path}`);
      }
    );
  };
}

export class WaveTextures {
  loadedCount = 0;
  textureData = [
    new WaveTexture("data:image/png;base64,", RepeatWrapping, RepeatWrapping),
    new WaveTexture("data:image/png;base64,", RepeatWrapping, RepeatWrapping),
    new WaveTexture("data:image/png;base64,", RepeatWrapping, RepeatWrapping),
  ];

  textureLoadedFn = (loadedFn) => {
    this.loadedCount++;
    if (this.loadedCount === this.textureData.length) {
      this.paletteTexture = this.textureData[0].texture;
      this.lutTexture = this.textureData[1].texture;
      this.blueNoiseTexture = this.textureData[2].texture;
      loadedFn();
    }
  };

  constructor(loadedFn) {
    this.loadedCount = 0;
    this.textureData.forEach((texture) => {
      texture.load(() => {
        this.textureLoadedFn(loadedFn);
      });
    });
  }

  paletteTexture = null;
  lutTexture = null;
  blueNoiseTexture = null;
}
